import React from 'react';
import { Input, MoneyInput } from '@linm-soft/common-components';
import { CustomerSearchField, AccountSearchInput } from '../../../../../components/search';
import { erpFinanceAccountSearchApi, formatAccountDisplay } from '../../../../../components/search/accountSearchApi';
import { formatMoneyVnd } from '../../../../../utils/formatters';
import type { CashVoucherFormViewModel } from '../hooks/useCashVoucherFormController';
import styles from '../../../../../styles/documentForm.module.css';

export const CashVoucherLinesSection: React.FC<{ vm: CashVoucherFormViewModel }> = ({ vm }) => {
  const {
    labels,
    tid,
    viewSectionClass,
    showLineCustomer,
    showInvoiceGrid,
    isReadOnly,
    formState,
    lines,
    searchFieldClass,
    searchDisabled,
    ph,
    fieldLockProps,
    staticFieldProps,
    handleUpdateLine,
    resolveInvoiceForLine,
    fieldErrors,
    lineAccountSearchClass,
    handleRemoveLine,
    handleAddLine,
  } = vm;

  return (
    <div
      className={[styles.section, viewSectionClass].filter(Boolean).join(' ')}
      id={tid('section-lines')}
      data-testid={tid('section-lines')}
    >
      <h2 className={styles.sectionTitle}>{labels.sectionLines}</h2>
      <div className={styles.tableWrapper}>
        <table className={styles.linesTable}>
          <thead>
            <tr>
              {showLineCustomer && <th>{labels.lineCustomer}</th>}
              {showInvoiceGrid ? (
                <>
                  <th>{labels.invoiceCode}</th>
                  <th>{labels.invoiceDate}</th>
                  <th>{labels.invoiceTotal}</th>
                  <th>{labels.invoicePaid}</th>
                  <th>{labels.invoiceRemaining}</th>
                  <th className={styles.thAmount}>{labels.lineAmount}</th>
                  <th className={styles.thDesc}>{labels.lineDesc}</th>
                </>
              ) : (
                <>
                  <th className={styles.thAccount}>{labels.lineThAccount}</th>
                  <th className={styles.thAmount}>{labels.lineAmount}</th>
                  <th>{labels.costCenter}</th>
                  <th className={styles.thDesc}>{labels.lineDesc}</th>
                </>
              )}
              {!isReadOnly && <th className={styles.thDel} />}
            </tr>
          </thead>
          <tbody>
            {formState.lineRows.map((lineState, idx) => {
              const line = lines[idx];
              return (
                <tr key={lineState.lineId} data-testid={tid(`line-${idx}`)}>
                  {showLineCustomer && (
                    <td data-testid={tid(`line-${idx}-customer`)}>
                      <CustomerSearchField
                        testIdPrefix={tid(`line-${idx}-customer`)}
                        className={searchFieldClass}
                        customerId={line.customerId}
                        customerCode={line.customerCode}
                        customerName={line.customerName}
                        onSelect={c => handleUpdateLine(idx, {
                          customerId: c.customerId,
                          customerCode: c.code,
                          customerName: c.name,
                        })}
                        onClear={() => handleUpdateLine(idx, {
                          customerId: '',
                          customerCode: '',
                          customerName: '',
                        })}
                        placeholder={ph('Đối tượng...')}
                        disabled={searchDisabled}
                      />
                    </td>
                  )}
                  {showInvoiceGrid ? (
                    <>
                      <td data-testid={tid(`line-${idx}-invoiceCode`)}>
                        <Input
                          value={line.invoiceCode}
                          onChange={e => handleUpdateLine(idx, { invoiceCode: e.target.value })}
                          onBlur={e => { void resolveInvoiceForLine(idx, e.target.value); }}
                          placeholder={ph('Số HĐ...')}
                          {...fieldLockProps}
                        />
                      </td>
                      <td data-testid={tid(`line-${idx}-invoiceDate`)}>
                        <Input value={line.invoiceDate} {...staticFieldProps} />
                      </td>
                      <td data-testid={tid(`line-${idx}-invoiceTotal`)}>
                        <Input value={formatMoneyVnd(line.invoiceTotalAmount)} {...staticFieldProps} />
                      </td>
                      <td data-testid={tid(`line-${idx}-invoicePaid`)}>
                        <Input value={formatMoneyVnd(line.invoicePaidAmount)} {...staticFieldProps} />
                      </td>
                      <td data-testid={tid(`line-${idx}-invoiceRemaining`)}>
                        <Input value={formatMoneyVnd(line.invoiceRemainingAmount)} {...staticFieldProps} />
                      </td>
                      <td id={tid(`line-${idx}-amount`)} data-testid={tid(`line-${idx}-amount`)}>
                        <MoneyInput
                          value={Number(line.debitAmount)}
                          error={fieldErrors.lines?.[idx]?.debitAmount}
                          onChange={amount => handleUpdateLine(idx, { debitAmount: amount })}
                          {...fieldLockProps}
                        />
                      </td>
                      <td>
                        <Input
                          value={line.description}
                          onChange={e => handleUpdateLine(idx, { description: e.target.value })}
                          placeholder={ph('Nội dung...')}
                          {...fieldLockProps}
                        />
                      </td>
                    </>
                  ) : (
                    <>
                      <td id={tid(`line-${idx}-account`)} data-testid={tid(`line-${idx}-account`)}>
                        <AccountSearchInput
                          api={erpFinanceAccountSearchApi}
                          className={lineAccountSearchClass}
                          value={line.accountCode}
                          primaryDisplay={formatAccountDisplay(line.accountCode, line.accountName)}
                          error={fieldErrors.lines?.[idx]?.accountCode}
                          onChange={a => handleUpdateLine(idx, { accountCode: a.code, accountName: a.name })}
                          onClear={() => handleUpdateLine(idx, { accountCode: '', accountName: '' })}
                          placeholder={ph('TK')}
                          showSecondaryInput={false}
                          disabled={searchDisabled}
                        />
                      </td>
                      <td id={tid(`line-${idx}-amount`)} data-testid={tid(`line-${idx}-amount`)}>
                        <MoneyInput
                          value={Number(line.debitAmount)}
                          error={fieldErrors.lines?.[idx]?.debitAmount}
                          onChange={amount => handleUpdateLine(idx, { debitAmount: amount })}
                          {...fieldLockProps}
                        />
                      </td>
                      <td data-testid={tid(`line-${idx}-costCenter`)}>
                        <Input
                          value={line.costCenterCode}
                          onChange={e => handleUpdateLine(idx, { costCenterCode: e.target.value })}
                          placeholder={ph('Mã VV...')}
                          {...fieldLockProps}
                        />
                      </td>
                      <td>
                        <Input
                          value={line.description}
                          onChange={e => handleUpdateLine(idx, { description: e.target.value })}
                          placeholder={ph('Nội dung...')}
                          {...fieldLockProps}
                        />
                      </td>
                    </>
                  )}
                  {!isReadOnly && (
                    <td>
                      <button
                        type="button"
                        className={styles.btnDeleteLine}
                        onClick={() => handleRemoveLine(idx)}
                        title="Xóa dòng"
                      >
                        <i className="fas fa-trash-alt" aria-hidden="true" />
                      </button>
                    </td>
                  )}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {!isReadOnly && (
        <button
          type="button"
          className={styles.btnAddLine}
          data-testid={tid('add-line-btn')}
          onClick={handleAddLine}
        >
          {labels.addLine}
        </button>
      )}
    </div>
  );
};
